const daysBack = 90;
const since = new Date();
since.setDate(since.getDate() - daysBack);
const sinceStr = since.toISOString().replace(/\.\d{3}Z$/, '');
return [{ json: { since: sinceStr, daysBack } }];

// HTTP Request returns one item per matter; collect all incoming items.
const matters = $input.all().map((i) => i.json);

const typeCounts = {};
const statusCounts = {};
const notable = [];

for (const m of matters) {
  const type = m.MatterTypeName ?? 'Unknown';
  const status = m.MatterStatusName ?? 'Unknown';

  typeCounts[type] = (typeCounts[type] ?? 0) + 1;
  statusCounts[status] = (statusCounts[status] ?? 0) + 1;

  // Include common council outcomes so notable items are surfaced in Dallas data.
  const isNotableStatus = [
    'Passed',
    'Adopted',
    'Approved',
    'Hearing Closed; Approved',
    'Hearing Closed; Approved as Amended',
  ].some((s) => status.includes(s));

  if (isNotableStatus && notable.length < 10) {
    notable.push({
      type,
      title: (m.MatterTitle ?? '').substring(0, 200),
      status,
      date: m.MatterLastModifiedUtc,
    });
  }
}

const { daysBack } = $('Build Date Window').first().json;

return [{
  json: {
    city: 'Dallas',
    daysBack,
    total: matters.length,
    byType: typeCounts,
    byStatus: statusCounts,
    notable,
  }
}];
